export default function Checkin({ userId, onOpenGarden, onStateChange, onToneChange }) {
  const [state, setState] = useState("idle") // idle, loading, question, recording, analyzing, done
  const [question, setQuestion] = useState("")
  const [sessionId, setSessionId] = useState(null)
  const [history, setHistory] = useState([])
  const [exchangeCount, setExchangeCount] = useState(0)
  const [alert, setAlert] = useState(null)
  const [error, setError] = useState(null)
  const [report, setReport] = useState(null)
  const [recordingTime, setRecordingTime] = useState(0)
  const [lastTranscript, setLastTranscript] = useState("")
  const [isLeafSpinning, setIsLeafSpinning] = useState(false)
  const mediaRef = useRef(null)
  const chunksRef = useRef([])
  const timerRef = useRef(null)

  // Sync state with global parent to drive Lumie companion animations
  useEffect(() => {
    if (onStateChange) onStateChange(state)
  }, [state, onStateChange])

  useEffect(() => {
    if (onToneChange) {
      onToneChange(lastTranscript || (report ? "happy" : ""))
    }
  }, [lastTranscript, report, onToneChange])
